// // This SR latch will asynchronously set Q to 0 when S is high and asynchronously reset Q to 1 when R is high.
module sr_latch(  
    input wire clk,  
    input wire S,  
    input wire R,  
    output reg Q  
);  
always @(posedge clk) begin  
    if (S)  
        Q <= 1;  
    else if (R)  
        Q <= 0;  
end  
endmodule
